class InputValidator:
    """Validates and sanitizes input images to prevent adversarial attacks."""

    @staticmethod
    def validate_file_extension(filename: str) -> bool:
        """Check file extension against allowlist."""
        if not filename:
            return False
        ext = os.path.splitext(filename.lower())[1]
        return ext in ALLOWED_EXTENSIONS

    @staticmethod
    def validate_image_content(image_bytes: bytes) -> bool:
        """Validate image magic bytes to ensure it's a real image."""
        magic_bytes = {
            b'\xff\xd8\xff': 'jpeg',
            b'\x89PNG\r\n\x1a\n': 'png',
            b'BM': 'bmp',
            b'GIF87a': 'gif',
            b'GIF89a': 'gif',
            b'RIFF': 'webp',
        }
        for magic, fmt in magic_bytes.items():
            if image_bytes[:len(magic)] == magic:
                return True
        return False

    @staticmethod
    def validate_image_dimensions(image: Image.Image) -> bool:
        """Reject images with suspicious dimensions."""
        w, h = image.size
        if w <= 0 or h <= 0:
            return False
        if w > MAX_IMAGE_DIMENSION or h > MAX_IMAGE_DIMENSION:
            return False
        if w * h > MAX_IMAGE_DIMENSION * MAX_IMAGE_DIMENSION:
            return False
        return True

    @staticmethod
    def compute_hash(image_bytes: bytes) -> str:
        """Compute SHA-256 hash for audit logging."""
        return hashlib.sha256(image_bytes).hexdigest()


class AdversarialDefense:
    """Implements defenses against ML adversarial examples."""

    def __init__(self):
        self.jpeg_quality = 75
        self.spatial_smoothing_kernel = 3
        self.num_inference_passes = 5  # For randomized smoothing
        self.noise_std = 0.05  # Gaussian noise standard deviation

    def jpeg_compression_defense(self, image: Image.Image) -> Image.Image:
        """
        JPEG compression defense: re-encode image to remove high-frequency
        adversarial perturbations that don't survive lossy compression.
        """
        buffer = io.BytesIO()
        # Convert to RGB if necessary (JPEG doesn't support alpha)
        if image.mode != 'RGB':
            image = image.convert('RGB')
        image.save(buffer, format='JPEG', quality=self.jpeg_quality)
        buffer.seek(0)
        return Image.open(buffer).copy()

    def spatial_smoothing_defense(self, tensor: torch.Tensor) -> torch.Tensor:
        """
        Apply spatial smoothing (median filter approximation via average pooling)
        to reduce adversarial perturbations.
        """
        k = self.spatial_smoothing_kernel
        # Use average pooling as a smoothing operation
        padding = k // 2
        # tensor shape: [1, C, H, W]
        smoothed = F.avg_pool2d(tensor, kernel_size=k, stride=1, padding=padding)
        return smoothed

    def bit_depth_reduction(self, tensor: torch.Tensor, bits: int = 5) -> torch.Tensor:
        """
        Reduce bit depth to remove fine-grained adversarial perturbations.
        Quantize pixel values to fewer discrete levels.
        """
        levels = 2 ** bits
        quantized = torch.round(tensor * (levels - 1)) / (levels - 1)
        return quantized

    def randomized_smoothing(self, model: nn.Module, tensor: torch.Tensor) -> torch.Tensor:
        """
        Randomized smoothing: run multiple inference passes with added
        Gaussian noise and average the predictions. This provides
        certified robustness against L2-bounded adversarial perturbations.
        """
        all_logits = []
        model.eval()
        with torch.no_grad():
            for _ in range(self.num_inference_passes):
                noise = torch.randn_like(tensor) * self.noise_std
                noisy_input = torch.clamp(tensor + noise, 0.0, 1.0)
                # Re-normalize after adding noise
                noisy_normalized = normalize_tensor(noisy_input)
                logits = model(noisy_normalized)
                all_logits.append(logits)

        # Average logits across all passes
        avg_logits = torch.mean(torch.stack(all_logits), dim=0)
        return avg_logits

    def input_transformation_ensemble(self, image: Image.Image) -> Image.Image:
        """
        Apply a series of input transformations that destroy adversarial
        perturbations while preserving semantic content.
        """
        # Step 1: JPEG compression
        image = self.jpeg_compression_defense(image)

        # Step 2: Slight resize (destroys pixel-aligned perturbations)
        w, h = image.size
        # Resize down slightly then back up
        scale_factor = 0.95
        small_size = (max(1, int(w * scale_factor)), max(1, int(h * scale_factor)))
        image = image.resize(small_size, Image.BILINEAR)
        image = image.resize((w, h), Image.BILINEAR)

        return image


# Preprocessing pipeline
def get_preprocessing_transform():
    """Standard ImageNet preprocessing with deterministic transforms only."""
    return transforms.Compose([
        transforms.Resize(256),
        transforms.CenterCrop(INPUT_SIZE),
        transforms.ToTensor(),
    ])


def normalize_tensor(tensor: torch.Tensor) -> torch.Tensor:
    """Apply ImageNet normalization to tensor."""
    mean = torch.tensor([0.485, 0.456, 0.406]).view(1, 3, 1, 1).to(tensor.device)
    std = torch.tensor([0.229, 0.224, 0.225]).view(1, 3, 1, 1).to(tensor.device)
    return (tensor - mean) / std


