def run_secure_inference(image: Image.Image) -> Dict[str, Any]:
    """
    Run inference with full adversarial defense pipeline.

    Defense layers:
    1. Input transformation ensemble (JPEG compression + resize)
    2. Bit depth reduction
    3. Spatial smoothing
    4. Randomized smoothing (multiple noisy inference passes)
    5. Confidence thresholding
    """
    # Ensure RGB
    if image.mode != 'RGB':
        image = image.convert('RGB')

    # Defense Layer 1: Input transformation ensemble
    defended_image = adversarial_defense.input_transformation_ensemble(image)

    # Standard preprocessing
    tensor = preprocess(defended_image).unsqueeze(0).to(device)

    # Defense Layer 2: Bit depth reduction
    tensor = adversarial_defense.bit_depth_reduction(tensor, bits=5)

    # Defense Layer 3: Spatial smoothing
    tensor = adversarial_defense.spatial_smoothing_defense(tensor)

    # Defense Layer 4: Randomized smoothing (multiple noisy passes)
    avg_logits = adversarial_defense.randomized_smoothing(model, tensor)

    # Also run a clean pass for comparison (detect potential adversarial input)
    with torch.no_grad():
        clean_normalized = normalize_tensor(tensor)
        clean_logits = model(clean_normalized)

    # Compute probabilities
    avg_probs = F.softmax(avg_logits, dim=1)
    clean_probs = F.softmax(clean_logits, dim=1)

    # Defense Layer 5: Consistency check between clean and smoothed predictions
    avg_top_class = torch.argmax(avg_probs, dim=1).item()
    clean_top_class = torch.argmax(clean_probs, dim=1).item()

    # Use the smoothed prediction (more robust)
    confidence, predicted_class = torch.max(avg_probs, dim=1)
    confidence = confidence.item()
    predicted_class = predicted_class.item()

    # Flag if clean and smoothed predictions disagree (potential adversarial input)
    is_suspicious = avg_top_class != clean_top_class

    # Compute prediction entropy as additional adversarial indicator
    entropy = -torch.sum(avg_probs * torch.log(avg_probs + 1e-10), dim=1).item()

    # Get class label
    class_label = IMAGENET_LABELS[predicted_class] if predicted_class < len(IMAGENET_LABELS) else f"class_{predicted_class}"

    # Get top-5 predictions
    top5_probs, top5_indices = torch.topk(avg_probs, 5, dim=1)
    top5 = []
    for i in range(5):
        idx = top5_indices[0][i].item()
        prob = top5_probs[0][i].item()
        label = IMAGENET_LABELS[idx] if idx < len(IMAGENET_LABELS) else f"class_{idx}"
        top5.append({"class_id": idx, "class_label": label, "confidence": round(prob, 6)})

    result = {
        "predicted_class_id": predicted_class,
        "predicted_class_label": class_label,
        "confidence": round(confidence, 6),
        "top5_predictions": top5,
        "prediction_entropy": round(entropy, 6),
        "adversarial_flags": {
            "prediction_inconsistency": is_suspicious,
            "low_confidence": confidence < CONFIDENCE_THRESHOLD,
            "high_entropy": entropy > 5.0,
        }
    }

    if is_suspicious:
        logger.warning(
            f"Potential adversarial input detected: clean prediction={clean_top_class}, "
            f"smoothed prediction={avg_top_class}"
        )
        result["warning"] = "Prediction inconsistency detected - input may be adversarial"

    if confidence < CONFIDENCE_THRESHOLD:
        result["warning"] = result.get("warning", "") + " Low confidence prediction."

    return result


