@app.route('/predict', methods=['POST'])
def predict():
    """
    Image classification endpoint with adversarial defenses.

    Accepts: multipart/form-data with 'image' file field
    Returns: JSON with predicted class, confidence, and adversarial flags
    """
    try:
        # Validate request has file
        if 'image' not in request.files:
            return jsonify({"error": "No image file provided. Use 'image' field."}), 400

        file = request.files['image']

        if file.filename == '':
            return jsonify({"error": "No file selected."}), 400

        # Validate file extension
        if not input_validator.validate_file_extension(file.filename):
            return jsonify({
                "error": f"Invalid file type. Allowed: {', '.join(ALLOWED_EXTENSIONS)}"
            }), 400

        # Read file bytes
        image_bytes = file.read()

        if len(image_bytes) == 0:
            return jsonify({"error": "Empty file uploaded."}), 400

        if len(image_bytes) > MAX_CONTENT_LENGTH:
            return jsonify({"error": f"File too large. Max size: {MAX_CONTENT_LENGTH} bytes."}), 400

        # Validate magic bytes
        if not input_validator.validate_image_content(image_bytes):
            return jsonify({"error": "File content does not match a supported image format."}), 400

        # Compute hash for audit trail
        image_hash = input_validator.compute_hash(image_bytes)
        logger.info(f"Processing image: hash={image_hash}, size={len(image_bytes)} bytes")

        # Open and validate image
        try:
            image = Image.open(io.BytesIO(image_bytes))
            image.load()  # Force full decode to catch corrupt images
        except Exception as e:
            logger.warning(f"Failed to decode image: {e}")
            return jsonify({"error": "Could not decode image file."}), 400

        # Validate dimensions
        if not input_validator.validate_image_dimensions(image):
            return jsonify({
                "error": f"Image dimensions out of range. Max: {MAX_IMAGE_DIMENSION}x{MAX_IMAGE_DIMENSION}"
            }), 400

        # Run secure inference with adversarial defenses
        result = run_secure_inference(image)
        result["image_hash"] = image_hash

        logger.info(
            f"Prediction: class={result['predicted_class_label']}, "
            f"confidence={result['confidence']}, "
            f"suspicious={result['adversarial_flags']['prediction_inconsistency']}"
        )

        return jsonify(result), 200

    except Exception as e:
        logger.error(f"Inference error: {e}", exc_info=True)
        return jsonify({"error": "Internal server error during inference."}), 500


@app.route('/predict/batch', methods=['POST'])
def predict_batch():
    """
    Batch image classification endpoint.
    Accepts multiple images in a single request.
    """
    try:
        files = request.files.getlist('images')

        if not files:
            return jsonify({"error": "No images provided. Use 'images' field."}), 400

        if len(files) > 16:
            return jsonify({"error": "Maximum 16 images per batch request."}), 400

        results = []
        for idx, file in enumerate(files):
            try:
                if not input_validator.validate_file_extension(file.filename):
                    results.append({"index": idx, "error": "Invalid file type", "filename": file.filename})
                    continue

                image_bytes = file.read()

                if not input_validator.validate_image_content(image_bytes):
                    results.append({"index": idx, "error": "Invalid image content", "filename": file.filename})
                    continue

                image = Image.open(io.BytesIO(image_bytes))
                image.load()

                if not input_validator.validate_image_dimensions(image):
                    results.append({"index": idx, "error": "Invalid dimensions", "filename": file.filename})
                    continue

                result = run_secure_inference(image)
                result["index"] = idx
                result["filename"] = file.filename
                result["image_hash"] = input_validator.compute_hash(image_bytes)
                results.append(result)

            except Exception as e:
                logger.warning(f"Error processing batch image {idx}: {e}")
                results.append({"index": idx, "error": "Processing failed", "filename": file.filename})

        return jsonify({"results": results, "total": len(results)}), 200

    except Exception as e:
        logger.error(f"Batch inference error: {e}", exc_info=True)
        return jsonify({"error": "Internal server error during batch inference."}), 500


